#ifdef class_T
typedef class_T T_type;
#else
typedef float T_type;
#endif

inline T_type conv_int(const int i) {
    return (T_type)i;
}

inline T_type mad_op(const T_type a, const T_type b, const T_type c) {
    return a * b + c;
}

inline int equal_op(const T_type a, const T_type b) {
    return (a == b);
}

